/* ===== 步骤条组件样式 ===== */

/* 基础横向步骤条 */
.stepper{display:flex;align-items:flex-start;padding:1rem 0;counter-reset:step}
.step{flex:1;text-align:center;position:relative;counter-increment:step}
.step:not(:last-child)::after{
  content:'';position:absolute;top:16px;left:calc(50% + 18px);
  width:calc(100% - 36px);height:2px;
  background:var(--gray);transition:background .4s;
}
.step.completed:not(:last-child)::after{background:var(--green)}
.step.active:not(:last-child)::after{background:linear-gradient(to right,var(--green),var(--gray))}

.step .step-dot{
  width:32px;height:32px;border-radius:50%;
  background:white;border:2px solid var(--gray);
  display:inline-flex;align-items:center;justify-content:center;
  font-size:.75rem;font-weight:700;color:#94a3b8;
  margin-bottom:.4rem;transition:all .3s;position:relative;z-index:1;
}
.step .step-dot::before{content:counter(step);}
.step.completed .step-dot{background:var(--green);border-color:var(--green);color:white;}
.step.completed .step-dot::before{content:'\2713';font-weight:900;}
.step.active .step-dot{background:white;border-color:var(--blue);color:var(--blue);box-shadow:0 0 0 4px rgba(59,130,246,.12);}
.step.pending .step-dot{background:#f1f5f9;border-color:#e2e8f0;color:#94a3b8;}

.step .step-label{font-size:.8rem;font-weight:500;color:#94a3b8;transition:color .3s}
.step.completed .step-label{color:var(--green)}
.step.active .step-label{color:var(--blue);font-weight:700}

/* 垂直步骤条 */
.stepper-vertical{display:flex;flex-direction:column;gap:0;padding:.5rem 0}
.step-v{display:flex;gap:1rem;position:relative;padding-bottom:1.5rem}
.step-v:not(:last-child)::before{
  content:'';position:absolute;top:36px;left:15px;
  width:2px;height:calc(100% - 20px);
  background:var(--gray);transition:background .4s;
}
.step-v.completed:not(:last-child)::before{background:var(--green)}
.step-v .v-dot{
  width:32px;height:32px;border-radius:50%;flex-shrink:0;
  background:white;border:2px solid var(--gray);
  display:flex;align-items:center;justify-content:center;
  font-size:.75rem;font-weight:700;color:#94a3b8;
  transition:all .3s;position:relative;z-index:1;
}
.step-v.completed .v-dot{background:var(--green);border-color:var(--green);color:white}
.step-v.active .v-dot{background:white;border-color:var(--blue);color:var(--blue);box-shadow:0 0 0 4px rgba(59,130,246,.12)}
.step-v .v-content{flex:1}
.step-v .v-title{font-size:.85rem;font-weight:600;color:#1e293b;margin-bottom:.2rem}
.step-v .v-desc{font-size:.75rem;color:#94a3b8}
.step-v.completed .v-title{color:var(--green)}
.step-v.active .v-title{color:var(--blue)}

/* 可点击步骤条 */
.stepper-clickable .step{cursor:pointer}
.stepper-clickable .step:hover .step-dot{border-color:var(--blue)}
.stepper-clickable .step.completed:hover .step-dot{border-color:var(--green)}

/* 交互式演示面板 */
.stepper-demo-panel{text-align:center}
.stepper-demo-panel .step-actions{display:flex;gap:.6rem;justify-content:center;margin-top:1rem}
.stepper-demo-panel .step-actions button{
  padding:.5rem 1.4rem;border:none;border-radius:8px;
  font-size:.82rem;font-weight:600;cursor:pointer;font-family:inherit;transition:all .2s;
}
.step-actions .btn-prev{background:#f1f5f9;color:#475569}
.step-actions .btn-prev:hover{background:#e2e8f0}
.step-actions .btn-next{background:var(--blue);color:white}
.step-actions .btn-next:hover{background:#2563eb}
.step-actions .btn-submit{background:var(--green);color:white}
.step-actions .btn-submit:hover{background:#16a34a}

@media(max-width:640px){
  .stepper{flex-direction:column;gap:.5rem}
  .step:not(:last-child)::after{display:none}
}

