// ===== 交互式步骤条控制器 =====
let currentStep = 1;
const totalSteps = 4;

function moveStep(delta) {
  const newStep = currentStep + delta;
  if (newStep < 1 || newStep > totalSteps) return;
  currentStep = newStep;
  updateStepper();
}

function updateStepper() {
  const steps = document.querySelectorAll('#stepper1 .step');
  steps.forEach((step, i) => {
    step.classList.remove('active', 'completed', 'pending');
    if (i + 1 < currentStep) step.classList.add('completed');
    else if (i + 1 === currentStep) step.classList.add('active');
    else step.classList.add('pending');
  });

  document.getElementById('prevBtn').disabled = currentStep === 1;
  const nextBtn = document.getElementById('nextBtn');
  if (currentStep === totalSteps) {
    nextBtn.textContent = '✓ 完成提交';
    nextBtn.className = 'btn-submit';
  } else {
    nextBtn.textContent = '下一步 →';
    nextBtn.className = 'btn-next';
  }
  document.getElementById('stepStatus').textContent = `当前：第 ${currentStep} 步 / 共 ${totalSteps} 步`;
}

// 点击步骤直接跳转
document.querySelectorAll('#stepper1 .step').forEach((step, i) => {
  step.addEventListener('click', () => {
    if (i + 1 < currentStep) { currentStep = i + 1; updateStepper(); }
  });
});

// 初始化
updateStepper();
